// Phase 29-05: thin caller -- prompt-construction, schema/few-shot text, and
// the live existing-entity fetch now live entirely in data-service's
// /context/assemble (dg_context.assemble_context()). This node only:
// (1) detects edit-mode from the raw rules_text (routing decision, not
//     Cypher validation -- kept here because /context/assemble does not
//     know which Rule_Id(s) an edit prompt targets), and
// (2) string-joins the assembled context dict into the final LLM prompt.
//
// NOTE (known limitation vs. pre-Phase-29 behavior): the original node
// also scored prompt keywords against EXISTING RULE TEXT to infer an edit
// target when no explicit Rule_Id was mentioned. dg_context.fetch_existing_entities()
// (ported in Plan 29-03) only unions Class/DatatypeProperty/ObjectProperty
// entities, not Rule text, so that scoring fallback is not reproducible from
// /context/assemble's response. Edit detection here is now Rule_Id-mention-only.
const input = $items("Set Input Defaults")[0].json;
const context = $json;

const rulesText = (input.rules_text || '')
  .replace(/[ \t]+/g, ' ')
  .replace(/\n{3,}/g, '\n\n')
  .trim();
if (!rulesText) {
  throw new Error('rules_text is required');
}

const editPat = /\b(?:edit|update|change|modify|set|increase|decrease|raise|lower|adjust)\b/i;
const ruleIdPat = /(?:Rule_Id|rule[_ ]?id)\s*[:=\s]*\W*([A-Z_][A-Z0-9_]+)/gi;
const isEditPrompt = editPat.test(rulesText);
const editRuleIds = [];
let ruleIdMatch;
while ((ruleIdMatch = ruleIdPat.exec(rulesText)) !== null) { editRuleIds.push(ruleIdMatch[1]); }
const editRuleId = isEditPrompt && editRuleIds.length ? editRuleIds[0] : null;

const existingEntities = Array.isArray(context.existing_entities) ? context.existing_entities : [];
const entityLines = [];
if (existingEntities.length) {
  entityLines.push('EXISTING ENTITIES IN THE GRAPH (you MUST reuse these, do NOT create duplicates):');
  existingEntities.forEach((e) => {
    const disp = e.nodeLabel === 'Class' ? e.label : (e.swrl_label || e.label);
    entityLines.push('  - ' + disp + ' [' + e.nodeLabel + '] (iri: ' + e.iri + (e.range ? ', range: ' + e.range : '') + ')');
  });
}

const editGuidance = editRuleId ? (
  'EDIT MODE: You are EDITING existing rule(s): ' + editRuleIds.join(', ') + '.\n' +
  'Output the COMPLETE updated rule(s) with ALL nodes and relationships (MERGE+SET) from scratch.\n' +
  'Keep the same DatatypeProperty/Class iris from the original rule; only change the Literal lex value for numeric threshold edits.\n' +
  'Update Rule_Id to reflect the new numeric limit (e.g. R_..._1_V becomes R_..._2_V).\n' +
  'If the prompt adds new constraints, create those as SEPARATE new Rules.\n' +
  'NEVER output rules that were not mentioned in the edit prompt.'
) : '';

const prompt = [
  'Convert design rules into Neo4j Cypher MERGE + SET statements. Output Cypher only, no JSON, no markdown fences.',
  '',
  'CONTEXT (deterministically assembled by /context/assemble -- schema layers, SWRL conventions, and the matched Cypher catalog shape(s) with worked examples):',
  JSON.stringify({
    ontograph: context.ontograph,
    metagraph: context.metagraph,
    swrl_conventions: context.swrl_conventions,
    selected_cypher_shapes: context.selected_cypher_shapes
  }),
  '',
  "project = '" + input.project_name + "'",
  '',
  entityLines.join('\n'),
  '',
  editGuidance,
  '',
  'Now convert these rules (output ONLY the Cypher MERGE+SET statements, then stop):',
  rulesText
].join('\n');

return [{ json: { ...input, prompt, isEdit: !!editRuleId, editRuleIds: editRuleIds } }];

// Phase 29-05: thin caller -- bracket-nesting / label-allow-list validation
// no longer lives here. POST /context/generate-cypher (dg_context.generate_validated_cypher(),
// Plan 29-04) already ran validate_cypher() with a bounded 3-attempt retry
// loop before this node ever sees a response: {valid, cypher, attempts} on
// success, or {valid:false, violations, attempts} once retries are exhausted.
const input = $items("Set Input Defaults")[0].json;
const llmBuild = $items("Build LLM Prompt")[0].json;
const base = {
  project_name: input.project_name,
  neo4j_user: input.neo4j_user,
  neo4j_password: input.neo4j_password,
  neo4j_url: input.neo4j_url,
  rules_text: input.rules_text || '',
  isEdit: llmBuild.isEdit || false,
  editRuleIds: llmBuild.editRuleIds || []
};
const result = $json;
if (!result || result.valid !== true || !result.cypher) {
  const violations = (result && result.violations) || [];
  throw new Error('Cypher generation failed validation after retries: ' + JSON.stringify(violations));
}
return [{ json: { ...base, cypher: result.cypher } }];

const cypher = $json.cypher || '';
const project = $json.project_name || 'default-project';
const isEdit = $json.isEdit || false;
const editRuleIds = $json.editRuleIds || [];
let cleanupStatements = [];
if (isEdit && editRuleIds.length) {
  for (const rid of editRuleIds) {
    const safeId = rid.replace(/[^A-Za-z0-9_]/g, '');
    cleanupStatements.push(
      "MATCH (:Rule {Rule_Id: '" + safeId + "'})-[:HAS_BODY|HAS_HEAD]->(a:Atom)-[arg:ARG]->() DELETE arg",
      "MATCH (:Rule {Rule_Id: '" + safeId + "'})-[:HAS_BODY|HAS_HEAD]->(a:Atom)-[ref:REFERS_TO]->() DELETE ref",
      "MATCH (:Rule {Rule_Id: '" + safeId + "'})-[rel:HAS_BODY|HAS_HEAD]->(a:Atom) DELETE rel, a",
      "MATCH (r:Rule {Rule_Id: '" + safeId + "'}) DELETE r"
    );
  }
  cleanupStatements.push("MATCH (n) WHERE (n:Var OR n:Literal) AND n.graph = 'Metagraph' AND NOT (n)<-[:ARG]-() DELETE n");
}

const postProcess = [
  "MATCH (n) WHERE (n:Class OR n:DatatypeProperty OR n:ObjectProperty) AND n.graph IS NULL SET n.graph = 'OntoGraph', n.project = $project",
  "WITH 1 AS dummy",
  "MATCH (n) WHERE (n:Rule OR n:Atom OR n:Builtin OR n:Var OR n:Literal) AND n.graph IS NULL SET n.graph = 'Metagraph', n.project = $project",
  "WITH 1 AS dummy2",
  "MATCH (n) WHERE n.graph IS NULL SET n.graph = 'Metagraph', n.project = $project"
].join('\n');
const neo4j_auth_header = 'Basic ' + Buffer.from(($json.neo4j_user || 'neo4j') + ':' + ($json.neo4j_password || '12345678')).toString('base64');
return [{
  json: {
    neo4j_auth_header: neo4j_auth_header,
    project_name: $json.project_name,
    neo4j_user: $json.neo4j_user,
    neo4j_password: $json.neo4j_password,
    neo4j_url: $json.neo4j_url,
    rules_text: $json.rules_text || '',
    cypher: cypher,
    cleanupStatements: cleanupStatements,
    postProcess: postProcess
  }
}];

const payload = $items("Prepare Graph Payload")[0].json;
const cypher = payload.cypher || '';
const mergeCount = (cypher.match(/MERGE/gi) || []).length;
return [{
  json: {
    status: "ok",
    project: payload.project_name,
    database: "neo4j",
    graphs: { ontology: "OntoGraph", rules: "Metagraph" },
    counts: { merge_statements: mergeCount },
    cypher: cypher
  }
}];
